class LRUCache {
public:
    LRUCache(int capacity) {
        this->capacity = capacity;
    }

    int get(int key) {
        if (cache.find(key) == cache.end()) {
            return -1;
        }

        auto it = cache.find(key);
        if (++it->second.used_count > capacity) {
            cache.erase(it);
        }
        return it->second.value;
    }

    void put(int key, int value) {
        if (cache.find(key) != cache.end()) {
            cache[key].value = value;
        } else {
            cache[key] = CacheRecord(key, value, 0);
        }
    }

    private:
        struct CacheRecord {
            int key;
            int value;
            int used_count;
        };

        unordered_map<int, CacheRecord> cache;
};
```

